#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    void heapify(vector<int>& nums, int n, int i) {
        int largest = i;
        int left = 2 * i + 1;
        int right = 2 * i + 2;

        if (left < n && nums[left] > nums[largest])
            largest = left;

        if (right < n && nums[right] > nums[largest])
            largest = right;

        if (largest != i) {
            swap(nums[i], nums[largest]);
            heapify(nums, n, largest);
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    Solution sol;
    for (int i = n / 2 - 1; i >= 0; i--) {
        sol.heapify(nums, n, i);
    }
    cout << n << '\n';
    for (int i = 0; i < n; i++) {
        cout << nums[i] << (i == n - 1 ? '\n' : ' ');
    }
    return 0;
}
